        let shore = false;
        for (const [oi,oj] of [[ci-1,cj-1],[ci,cj-1],[ci-1,cj],[ci,cj]]) if (!cells.has(oi+','+oj)) { shore = true; break; }
        const t = Math.min(1, depth/4.5);
