          const hub = new THREE.Mesh(new THREE.CylinderGeometry(radius*0.42, radius*0.42, 0.26, 10), rmat); hub.rotation.z = Math.PI/2; hub.position.set(side*(RAIL_GAUGE/2), wy, wz); parent.add(hub); wheelSets.push(hub);
