    const L0=[-1.0,-.5,-.5],L1=[1.0,-.5,-.5],B0=[-.35,-.5,.9],B1=[.35,-.5,.9],T0=[-1.0,.5,-.5],T1=[1.0,.5,-.5];
    const tris=[[L0,L1,T1],[L0,T1,T0],[L0,B0,B1],[L0,B1,L1],[T0,T1,B1],[T0,B1,B0],[L0,T0,B0],[L1,B1,T1]];
