    // ---- update: advance the train, seat + orient each vehicle, spin wheels, puff smoke ----
    // state.head = loop-distance of the LOCO NOSE; L = loop length; carOffs = per-vehicle center
    // offsets behind the nose; trainLen = nose-to-tail extent. Exposed for train-CROSSING logic
    // (2026-07-13 R3): the game samples at(dist)/carWorld() to lower gates + rule kart contact.
    const trainLen = offs.length ? (offs[offs.length-1] + (vehLen[vehLen.length-1]/2)) : 0;
    const state = { head: 0, L, at, carOffs: offs.slice(), vehLen: vehLen.slice(), trainLen, kids };
